    private void loadStats() {
        try {
            String name = Session.getFullName();
            lblAdminName.setText(name);
            lblRole.setText("Role: Administrator");

            try (Connection conn = DatabaseManager.getConnection()) {
                lblTotalStudents .setText(String.valueOf(count(conn, "students")));
                lblTotalFaculty  .setText(String.valueOf(count(conn, "faculty")));
                lblTotalSections .setText(String.valueOf(count(conn, "sections")));
                lblTotalSubjects .setText(String.valueOf(count(conn, "subjects")));

                // Year-level breakdown
                lblY1.setText(String.valueOf(countWhere(conn,"students","year_level=1")));
                lblY2.setText(String.valueOf(countWhere(conn,"students","year_level=2")));
                lblY3.setText(String.valueOf(countWhere(conn,"students","year_level=3")));
                lblY4.setText(String.valueOf(countWhere(conn,"students","year_level=4")));
            }
        } catch (Exception e) {
            System.err.println("AdminDashboard loadStats: " + e.getMessage());
        }
    }

    private int count(Connection conn, String table) throws SQLException {
        ResultSet rs = conn.createStatement().executeQuery("SELECT COUNT(*) FROM " + table);
        return rs.next() ? rs.getInt(1) : 0;
    }

    private int countWhere(Connection conn, String table, String where) throws SQLException {
        ResultSet rs = conn.createStatement().executeQuery("SELECT COUNT(*) FROM " + table + " WHERE " + where);
        return rs.next() ? rs.getInt(1) : 0;
    }

    // ── FIX #3: Admin double-click — open Faculty dashboard with override ─────

    /**
     * Opens a Faculty dashboard in admin-proxy mode for the given faculty's user_id.
     * Call this from FacultiesWindow when the admin double-clicks a row:
     *
     *   table.addMouseListener(new MouseAdapter() {
     *       public void mouseClicked(MouseEvent e) {
     *           if (e.getClickCount() == 2) {
     *               int userId = getSelectedFacultyUserId(); // from your table model
     *               AdminDashboard.openFacultyAsAdmin(userId);
     *           }
     *       }
     *   });
     */
    public static void openFacultyAsAdmin(int facultyUserId) {
        Faculty f = new Faculty(facultyUserId, true);
        f.setLocationRelativeTo(null);
        f.setVisible(true);
    }

    /**
     * Opens a Student dashboard in admin-proxy mode for the given student's user_id.
     * Call this from StudentsWindow when the admin double-clicks a row:
     *
     *   table.addMouseListener(new MouseAdapter() {
     *       public void mouseClicked(MouseEvent e) {
     *           if (e.getClickCount() == 2) {
     *               int userId = getSelectedStudentUserId(); // from your table model
     *               AdminDashboard.openStudentAsAdmin(userId);
     *           }
     *       }
     *   });
     */
    public static void openStudentAsAdmin(int studentUserId) {
        StudentDashboard sd = new StudentDashboard(studentUserId, true);
        sd.setLocationRelativeTo(null);
        sd.setVisible(true);
    }

