    private void makeStatCard(javax.swing.JPanel parent, javax.swing.JPanel card,
                               javax.swing.JLabel lblTitle, String title,
                               javax.swing.JLabel lblVal, java.awt.Color bg, int x, int y) {
        card.setBackground(bg);
        card.setLayout(new org.netbeans.lib.awtextra.AbsoluteLayout());
        lblTitle.setFont(new java.awt.Font("Segoe UI", 0, 11));
        lblTitle.setForeground(java.awt.Color.WHITE);
        lblTitle.setText(title);
        card.add(lblTitle, new org.netbeans.lib.awtextra.AbsoluteConstraints(10, 60, -1, -1));
        lblVal.setFont(new java.awt.Font("Segoe UI", 1, 32));
        lblVal.setForeground(java.awt.Color.WHITE);
        lblVal.setText("0");
        card.add(lblVal, new org.netbeans.lib.awtextra.AbsoluteConstraints(18, 15, -1, -1));
        parent.add(card, new org.netbeans.lib.awtextra.AbsoluteConstraints(x, y, 150, 90));
    }

